#include <string>
#include <vector>
using namespace std;

long long solve(std::string s) {
    int n = s.size();
    vector<int> c_count(n + 1, 0);
    vector<int> t_count(n + 1, 0);

    // Precompute the number of 'C's after each position
    for (int i = n - 1; i >= 0; --i) {
        c_count[i] = c_count[i + 1] + (s[i] == 'C' ? 1 : 0);
    }

    // Precompute the number of 'T's after each position
    for (int i = n - 1; i >= 0; --i) {
        t_count[i] = t_count[i + 1] + (s[i] == 'T' ? 1 : 0);
    }

    long long original = 0;
    long long max_increase = 0;

    // Calculate original LCT count and potential increases
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'L') {
            original += c_count[i + 1] * t_count[i + 1];
        }
    }

    // Now, check for each possible insertion position
    for (int i = 0; i <= n; ++i) {
        long long current = 0;
        // Case 1: Insert 'L' at position i
        if (i > 0) {
            int l_pos = i - 1;
            while (l_pos >= 0 && s[l_pos] != 'L') {
                l_pos--;
            }
            if (l_pos >= 0) {
                // The new 'L' can pair with 'C's and 'T's after i
                current += c_count[i] * t_count[i];
            }
        } else {
            // Insert 'L' at the beginning
            current += c_count[0] * t_count[0];
        }

        // Case 2: Insert 'C' at position i
        // Find 'L's before i and 'T's after i
        int l_count = 0;
        for (int j = 0; j < i; ++j) {
            if (s[j] == 'L') {
                l_count++;
            }
        }
        current = max(current, (long long)l_count * t_count[i]);

        // Case 3: Insert 'T' at position i
        // Find 'L's before i and 'C's between them and i
        int c_after_l = 0;
        for (int j = 0; j < i; ++j) {
            if (s[j] == 'L') {
                c_after_l += c_count[j + 1] - c_count[i];
            }
        }
        current = max(current, (long long)c_after_l);

        max_increase = max(max_increase, current);
    }

    return original + max_increase;
}

